/**
 * PawVital Evaluation Harness (VET-1206)
 *
 * Scores live route benchmark artifacts generated by scripts/runpod-benchmark.mjs.
 * This replaces the old simulated-only harness for the Wave 2 quality loop.
 *
 * Usage:
 *   npx ts-node --esm scripts/eval-harness.ts --suite=data/benchmarks/dog-triage/gold-candidate
 *   npx ts-node --esm scripts/eval-harness.ts --input=runpod-benchmark-report.json
 *   npx ts-node --esm scripts/eval-harness.ts --case=emergency-bloat-gasdilation
 */

import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import { spawnSync } from "node:child_process";
import { pathToFileURL } from "node:url";

import type {
  LiveEvalFilter,
  LiveEvalScorecard,
  RouteBenchmarkReport,
} from "../src/lib/benchmark-live-eval";

interface EvalCliOptions {
  suite: string | null;
  input: string | null;
  artifactOutput: string | null;
  output: string | null;
  markdownOutput: string | null;
  baseUrl: string;
  skipPreflight: boolean;
  allowBlocked: boolean;
  filter: LiveEvalFilter;
}

const ROOT = process.cwd();
const DEFAULT_SUITE = path.join(
  ROOT,
  "data",
  "benchmarks",
  "dog-triage",
  "wave3-freeze"
);
const DEFAULT_ARTIFACT = path.join(ROOT, "runpod-benchmark-report.json");
const DEFAULT_SCORECARD = path.join(
  ROOT,
  "data",
  "benchmarks",
  "dog-triage",
  "live-scorecard.json"
);
const DEFAULT_MARKDOWN = path.join(
  ROOT,
  "plans",
  "eval-baseline-sidecar-stack.md"
);

async function loadBenchmarkLiveEval() {
  return import(
    pathToFileURL(
      path.join(ROOT, "src", "lib", "benchmark-live-eval.ts")
    ).href
  );
}

function parseArgs(argv: string[]): EvalCliOptions {
  const options: EvalCliOptions = {
    suite: null,
    input: null,
    artifactOutput: null,
    output: DEFAULT_SCORECARD,
    markdownOutput: null,
    baseUrl:
      process.env.APP_BASE_URL ||
      process.env.NEXT_PUBLIC_APP_URL ||
      "http://localhost:3000",
    skipPreflight: false,
    allowBlocked: false,
    filter: {},
  };

  for (const arg of argv) {
    if (arg.startsWith("--suite=")) {
      options.suite = path.resolve(ROOT, arg.slice("--suite=".length));
      continue;
    }
    if (arg.startsWith("--input=")) {
      options.input = path.resolve(ROOT, arg.slice("--input=".length));
      continue;
    }
    if (arg.startsWith("--artifact-output=")) {
      options.artifactOutput = path.resolve(
        ROOT,
        arg.slice("--artifact-output=".length)
      );
      continue;
    }
    if (arg.startsWith("--output=")) {
      options.output = path.resolve(ROOT, arg.slice("--output=".length));
      continue;
    }
    if (arg.startsWith("--markdown-output=")) {
      options.markdownOutput = path.resolve(
        ROOT,
        arg.slice("--markdown-output=".length)
      );
      continue;
    }
    if (arg.startsWith("--base-url=")) {
      options.baseUrl = arg.slice("--base-url=".length).trim();
      continue;
    }
    if (arg.startsWith("--case=")) {
      options.filter.caseId = arg.slice("--case=".length).trim();
      continue;
    }
    if (arg.startsWith("--response-type=")) {
      options.filter.responseType = arg.slice("--response-type=".length).trim();
      continue;
    }
    if (arg.startsWith("--risk-tier=")) {
      options.filter.riskTier = arg.slice("--risk-tier=".length).trim();
      continue;
    }
    if (arg.startsWith("--tag=")) {
      options.filter.tag = arg.slice("--tag=".length).trim();
      continue;
    }
    if (arg === "--skip-preflight") {
      options.skipPreflight = true;
      continue;
    }
    if (arg === "--allow-blocked") {
      options.allowBlocked = true;
      continue;
    }
  }

  return options;
}

function ensure(condition: unknown, message: string): asserts condition {
  if (!condition) {
    throw new Error(message);
  }
}

function readJson<T>(filePath: string): T {
  return JSON.parse(fs.readFileSync(filePath, "utf8")) as T;
}

function isRouteBenchmarkReport(value: unknown): value is RouteBenchmarkReport {
  if (!value || typeof value !== "object") return false;
  const candidate = value as Partial<RouteBenchmarkReport>;
  return (
    (candidate.mode === "live" ||
      candidate.mode === "dry-run" ||
      candidate.mode === "blocked") &&
    typeof candidate.suiteId === "string" &&
    Array.isArray(candidate.cases)
  );
}

function runLiveSuite(options: EvalCliOptions): string {
  const artifactOutput =
    options.artifactOutput ||
    path.join(os.tmpdir(), `pawvital-live-benchmark-${Date.now()}.json`);
  const args = [
    "scripts/runpod-benchmark.mjs",
    `--input=${options.suite}`,
    `--output=${artifactOutput}`,
    `--base-url=${options.baseUrl}`,
  ];

  if (options.skipPreflight) {
    args.push("--skip-preflight");
  }

  const result = spawnSync(process.execPath, args, {
    cwd: ROOT,
    stdio: "inherit",
    encoding: "utf8",
  });

  if (result.status !== 0) {
    throw new Error(
      `runpod-benchmark failed with status ${result.status ?? "unknown"}`
    );
  }

  return artifactOutput;
}

function printSummary(scorecard: LiveEvalScorecard) {
  console.log(`\n${"=".repeat(64)}`);
  console.log("PAWVITAL LIVE EVALUATION HARNESS");
  console.log(`${"=".repeat(64)}`);
  console.log(`Suite: ${scorecard.suiteId}`);
  console.log(`Base URL: ${scorecard.baseUrl || "unknown"}`);
  console.log(`Result: ${scorecard.passFail}`);
  console.log(`Cases: ${scorecard.totalCases}`);
  console.log(
    `Expectation pass rate: ${(scorecard.expectationPassRate * 100).toFixed(1)}%`
  );
  console.log(
    `Mean expectation score: ${(scorecard.meanExpectationScore * 100).toFixed(1)}%`
  );
  console.log(
    `Emergency recall: ${(scorecard.emergencyRecall * 100).toFixed(1)}% (${scorecard.emergencyCaseCount} cases)`
  );
  console.log(
    `Unsafe downgrade rate: ${(scorecard.unsafeDowngradeRate * 100).toFixed(2)}%`
  );
  console.log(`Blocking failures: ${scorecard.blockingFailures}`);

  if (scorecard.preflight) {
    console.log("\nPreflight:");
    console.log(
      `  ready=${scorecard.preflight.ready} configured=${scorecard.preflight.configuredCount}/${scorecard.preflight.requiredServices} healthy=${scorecard.preflight.healthyCount}/${scorecard.preflight.requiredServices} stub=${scorecard.preflight.stubCount}`
    );
    if (scorecard.preflight.blockers.length > 0) {
      for (const blocker of scorecard.preflight.blockers) {
        console.log(`  blocker: ${blocker}`);
      }
    }
  }

  if (scorecard.failures.length > 0) {
    console.log("\nTop failures:");
    for (const failure of scorecard.failures.slice(0, 10)) {
      console.log(
        `  [${failure.severity}] ${failure.caseId} ${failure.category} — ${failure.description}`
      );
    }
  }
}

function writeFile(filePath: string, contents: string) {
  fs.mkdirSync(path.dirname(filePath), { recursive: true });
  fs.writeFileSync(filePath, contents);
}

async function main() {
  const options = parseArgs(process.argv.slice(2));
  const { renderLiveScorecardMarkdown, scoreLiveBenchmarkReport } =
    await loadBenchmarkLiveEval();
  const artifactPath = options.suite
    ? runLiveSuite(options)
    : options.input || DEFAULT_ARTIFACT;

  ensure(fs.existsSync(artifactPath), `Benchmark artifact not found: ${artifactPath}`);
  const report = readJson<RouteBenchmarkReport>(artifactPath);
  ensure(
    isRouteBenchmarkReport(report),
    `Benchmark artifact is not a live route report: ${artifactPath}`
  );
  ensure(
    report.mode !== "dry-run",
    "Dry-run artifacts cannot be scored as live baselines"
  );

  const scorecard = scoreLiveBenchmarkReport(report, options.filter);
  scorecard.preflight = report.preflight || null;
  printSummary(scorecard);

  if (options.output) {
    writeFile(`${options.output}`, `${JSON.stringify(scorecard, null, 2)}\n`);
    console.log(`\nScorecard written to ${options.output}`);
  }

  const markdownOutput =
    options.markdownOutput || (options.suite ? DEFAULT_MARKDOWN : null);
  if (markdownOutput) {
    writeFile(markdownOutput, `${renderLiveScorecardMarkdown(scorecard)}\n`);
    console.log(`Markdown baseline written to ${markdownOutput}`);
  }

  process.exitCode =
    scorecard.passFail === "PASS" ||
    (scorecard.passFail === "BLOCKED" && options.allowBlocked)
      ? 0
      : 1;
}

void main();
